--
-- Create or alter function [SSop].[tvf_Quotes]
--
GO


CREATE OR ALTER FUNCTION [SSop].[tvf_Quotes]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
		q.FullNumber AS Number,
		LEFT(q.Overview, 200) AS Details, 
		acc.Name + N' / ' + agent.Name AS Account,
		uprn.FormattedAddressComma,
		qcf.QuoteStatus,
		i.FullName AS QuotingConsultant,
		ou.Name AS OrganisationalUnitName,
		jt.Name AS JobType
FROM    SSop.Quotes q
JOIN	SSop.Quote_CalculatedFields qcf ON (qcf.ID = q.ID)
JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
JOIN	SSop.Enquiries AS e ON (e.ID = es.EnquiryId)
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Properties uprn ON (uprn.ID = e.PropertyId)
JOIN	SCore.Identities i ON (i.ID = q.QuotingConsultantId)
JOIN    SCore.OrganisationalUnits ou ON q.OrganisationalUnitID = ou.ID
JOIN	SJob.JobTypes AS jt ON (jt.ID = es.JobTypeId)
WHERE   (q.RowStatus NOT IN (0, 254))
	AND	(q.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiryServices]
--
GO





CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiryServices]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS RETURN	
SELECT  es.ID,
        es.RowStatus,
        es.RowVersion,
        es.Guid,
		jt.Name AS JobType,
		q.FullNumber AS Quote,
		esei.QuoteNet, 
		CONCAT(srs.Number, ' - ', srs.Description) AS StartRibaStage,
		CONCAT(ers.Number, ' - ', ers.Description) AS EndRibaStage,
		CASE 
			WHEN q.ID < 0 THEN N'No Quote'
			WHEN q.DateDeclinedToQuote IS NOT NULL THEN N'Declined To Quote.' --NEW [CBLD-592]
			ELSE qcf.QuoteStatus END AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
JOIN	SSop.Quotes q ON (q.ID = esei.QuoteId)
JOIN	SSop.Quote_CalculatedFields AS qcf ON (qcf.ID = q.ID)
JOIN	SJob.JobTypes jt ON (jt.ID = es.JobTypeId)
JOIN	SJob.RibaStages srs ON (srs.ID = es.StartRibaStageId)
JOIN	SJob.RibaStages ers ON (ers.ID = es.EndRibaStageId)
JOIN	SSop.Enquiries enq ON (enq.ID = es.EnquiryId) --NEW [CBLD-592]
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(q.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(es.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
UNION ALL
SELECT  -1,
        1,
        null,
        '00000000-0000-0000-0000-000000000000',
		N'Total:' AS JobType,
		N'' AS Quote,
		SUM(esei.QuoteNet) AS QuoteNet, 
		N'' AS StartRibaStage,
		N'' AS EndRibaStage,
		N'' AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_CurrentQuotes]
--
GO






CREATE OR ALTER FUNCTION [SSop].[tvf_CurrentQuotes]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
		q.FullNumber AS Number,
		LEFT(q.Overview, 200) AS Details, 
		acc.Name + N' / ' + agent.Name AS Account,
		uprn.FormattedAddressComma,
		qcf.QuoteStatus,
		i.FullName AS QuotingConsultant,
		q.RevisionNumber,
		ou.Name AS OrganisationalUnitName
FROM    SSop.Quotes q
JOIN	SSop.Quote_CalculatedFields qcf ON (qcf.ID = q.ID)
JOIN	SCrm.Accounts acc ON (acc.ID = q.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = q.AgentAccountId)
JOIN	SJob.Properties uprn ON (uprn.ID = q.UprnId)
JOIN	SCore.Identities i ON (i.ID = q.QuotingConsultantId)
JOIN    SCore.OrganisationalUnits ou ON q.OrganisationalUnitID = ou.ID
WHERE   (q.RowStatus NOT IN (0, 254))
	AND	(q.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
	AND	(
			(q.DateAccepted IS NULL)
			OR 
			(
				(q.DateAccepted IS NOT NULL)
				AND (EXISTS 
						(
							SELECT	1
							FROM	SSop.QuoteItems qi
							JOIN	SSop.QuoteSections qs ON (qs.ID = qi.QuoteSectionId)
							WHERE	(qs.QuoteID = q.ID)
								AND	(qi.RowStatus NOT IN (0, 254))
								AND	(qi.CreatedJobId < 0)
						)
					)
			)
		)
	AND	(q.DateRejected IS NULL)
	AND	(q.ExpiryDate > GETDATE())
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Enquiry_CalculatedFields]
--
GO










CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
   --WITH SCHEMABINDING
AS
SELECT	e.ID,
		CASE
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.QuoteItems AS qi 
											WHERE	(qi.QuoteId = q.ID)
												AND	(qi.CreatedJobId < 0)
										)
									)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = e.ID)
												AND	(q2.DateAccepted IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND	(q2.DateRejected IS NULL)
										)
									)
					   )
				 ) THEN N'Complete'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q2.DateAccepted IS NULL) 
												AND	(q2.DateRejected IS NULL)
												AND	(q2.DeadDate IS NULL)
										)
									)
					   )
				 ) THEN N'Accepted'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q.DateAccepted IS NULL) 
										)
									)
					   )
				 ) THEN N'Part Accepted'

			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateRejected IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q.DateRejected IS NULL) 
										)
									)
					   )
				 ) THEN N'Rejected'
			WHEN e.ChaseDate1 IS NOT NULL THEN N'1st Chase'
			WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
			WHEN (EXISTS
				   (
					   SELECT 1
					   FROM SSop.EnquiryServices es
					   WHERE es.EnquiryId = e.ID
					   AND es.RowStatus NOT IN (0,254) -- Ensure active enquiry services
					   HAVING COUNT(es.ID) > 1 -- Ensure multiple services
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q
						   JOIN SSop.EnquiryServices es ON q.EnquiryServiceID = es.ID
						   WHERE es.EnquiryId = e.ID
						   AND es.RowStatus NOT IN (0,254)
						   AND q.DateSent IS NOT NULL
					   )
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q2
						   JOIN SSop.EnquiryServices es2 ON q2.EnquiryServiceID = es2.ID
						   WHERE es2.EnquiryId = e.ID
						   AND es2.RowStatus NOT IN (0,254)
						   AND q2.DateSent IS NULL
						   AND q2.DateRejected IS NULL
						   AND q2.DateDeclinedToQuote IS NULL
					   )
				   )
			) THEN N'Part Sent'
					WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateSent IS NOT NULL)
					   )
				 ) THEN N'Sent'
				
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
					   )
				 ) THEN N'Quoting'
			WHEN e.DeadDate IS NOT NULL THEN N'Dead'
			WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'
			WHEN e.IsReadyForQuoteReview = 1 THEN N'Ready for Quote'
			WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE ()) THEN N'Deadline Approaching'
			WHEN e.QuotingDeadlineDate < GETDATE () THEN N'Deadline Missed'
			ELSE N'New'
		END AS EnquiryStatus
FROM	SSop.Enquiries AS e;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SFin].[InvoiceRequestsDelete]
--
GO
CREATE OR ALTER PROCEDURE [SFin].[InvoiceRequestsDelete]
	@Guid UNIQUEIDENTIFIER 
AS
BEGIN
	
	IF(EXISTS
       (
           SELECT 1
           FROM SFin.TransactionDetails td
           INNER JOIN SFin.InvoiceRequestItems iri ON (iri.ID = td.InvoiceRequestItemId)
		   INNER JOIN SFin.InvoiceRequests ir ON (ir.ID = iri.InvoiceRequestId)
           WHERE (iri.InvoiceRequestId = ir.ID) AND ir.Guid = @Guid
       ))
	   BEGIN 
			;THROW 60000, N'Cannot Delete Completed Invoice Requests.', 1
			RETURN
	   END
	   --ELSE
		  -- BEGIN

					EXEC SCore.DeleteDataObject @Guid = @Guid	-- uniqueidentifier

					UPDATE	SFin.InvoiceRequests
					SET		RowStatus = 254
					WHERE	(Guid = @Guid)

		   --END;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[Job_FeeDrawdown]
--
GO









CREATE OR ALTER VIEW [SJob].[Job_FeeDrawdown] 
	    --WITH SCHEMABINDING
AS SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				CONVERT(NVARCHAR(10),
				rs.Number
				)
		END	  AS Stage,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				rs.Description
		END	  AS StageLabel,
		CASE rs.Number
				WHEN N'0' THEN
					(0 + ISNULL(Amendments.Stage0Change,
					0
					)
					)
				WHEN N'1' THEN
					(j.RibaStage1Fee + ISNULL(Amendments.Stage1Change,
					0
					)
					)
				WHEN N'2' THEN
					(j.RibaStage2Fee + ISNULL(Amendments.Stage2Change,
					0
					)
					)
				WHEN N'3' THEN
					(j.RibaStage3Fee + ISNULL(Amendments.Stage3Change,
					0
					)
					)
				WHEN N'4' THEN
					(j.RibaStage4Fee + ISNULL(Amendments.Stage4Change,
					0
					)
					)
				WHEN N'5' THEN
					(j.RibaStage5Fee + ISNULL(Amendments.Stage5Change,
					0
					)
					)
				WHEN N'6' THEN
					(j.RibaStage6Fee + ISNULL(Amendments.Stage6Change,
					0
					)
					)
				WHEN N'7' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.Stage7Change,
					0
					)
					)
				WHEN N'99' THEN
					(j.PreConstructionStageFee + ISNULL(Amendments.PreConstructionStageChange,
					0
					)
					)
				WHEN N'999' THEN
					(j.ConstructionStageFee + ISNULL(Amendments.ConstructionStageChange,
					0
					)
					)
				ELSE
				(j.FeeCap + ISNULL(Amendments.FeeCapChange,
				0
				)
				)
		END	  AS Agreed,
		SUM(ISNULL(td.Net,
		0
		))	  AS Invoiced,
		CASE rs.Number
				WHEN N'0' THEN
					0
				WHEN N'1' THEN
					j.RibaStage1Fee
				WHEN N'2' THEN
					j.RibaStage2Fee
				WHEN N'3' THEN
					j.RibaStage3Fee
				WHEN N'4' THEN
					j.RibaStage4Fee
				WHEN N'5' THEN
					j.RibaStage5Fee
				WHEN N'6' THEN
					j.RibaStage6Fee
				WHEN N'7' THEN
					j.RibaStage7Fee
				ELSE
				j.FeeCap
		END - SUM(ISNULL(td.Net,
		0
		))	  AS Remaining,

		-- QUOTEDMEETINGS
		CASE 
			WHEN rs.Number = N'0'  THEN 
				CASE 
					WHEN (Amendments.Stage0MeetingChange IS NULL OR Amendments.Stage0MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 1),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage0MeetingChange) AS INT)
				END
			WHEN rs.Number = N'1' THEN 
				CASE 
					WHEN (Amendments.Stage1MeetingChange IS NULL OR Amendments.Stage1MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 2),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage1MeetingChange) AS INT)
				END
			WHEN rs.Number = N'2'  THEN 
				CASE 
					WHEN (Amendments.Stage2MeetingChange IS NULL OR Amendments.Stage2MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 3),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage2MeetingChange) AS INT)
				END
			WHEN rs.Number = N'3'  THEN 
			CASE 
				WHEN (Amendments.Stage3MeetingChange IS NULL OR Amendments.Stage3MeetingChange = 0) 
					--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
					THEN CAST(
						ISNULL((SELECT ISNULL(qi.NumberOfMeetings, 0)
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 4),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage3MeetingChange) AS INT)
				END
			WHEN rs.Number = N'4' THEN 
			CASE
				WHEN (Amendments.Stage4MeetingChange IS NULL OR Amendments.Stage4MeetingChange = 0) 
					--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 5),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage4MeetingChange) AS INT)
				END
			WHEN rs.Number = N'5'  THEN
				CASE 
					WHEN (Amendments.Stage5MeetingChange IS NULL OR Amendments.Stage5MeetingChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 7),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage5MeetingChange) AS INT)
				END
			WHEN rs.Number = N'6'  THEN 
				CASE 
					WHEN (Amendments.Stage6MeetingChange IS NULL OR Amendments.Stage6MeetingChange = 0) 
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 8), 0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage6MeetingChange) AS INT)
				END
			WHEN rs.Number = N'7'  THEN 
				CASE 
					WHEN (Amendments.Stage7MeetingChange IS NULL OR Amendments.Stage7MeetingChange = 0) 
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 9),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage7MeetingChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99'  THEN 
				CASE 
					WHEN (Amendments.PreConstructionStageMeetingChange IS NULL OR Amendments.PreConstructionStageMeetingChange = 0)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.PreConstructionStageMeetingChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999' THEN
				CASE 
					WHEN (Amendments.ConstructionStageMeetingChange IS NULL OR Amendments.ConstructionStageMeetingChange = 0)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.ConstructionStageMeetingChange) AS INT)
				END
				ELSE CAST(
						ISNULL((SELECT SUM(ISNULL(qs.NumberOfMeetings, 0))
							FROM SSop.QuoteItems qi 
								LEFT JOIN SSop.QuoteSections qs ON (qs.ID = qi.QuoteSectionId)
							WHERE qi.CreatedJobId = j.ID),0)
					AS INT)
		END AS QuotedMeetings,

		ISNULL(Meetings.MeetingTotal,
		0
		)	  AS CompletedMeetings,

		-- QUOTEDSITEVISITS
		CASE 
			WHEN rs.Number = N'0'  THEN 
				CASE 
					WHEN (Amendments.Stage0VisitChange IS NULL OR Amendments.Stage0VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 1),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage0VisitChange) AS INT)
				END
			WHEN rs.Number = N'1'  THEN 
				CASE 
					WHEN (Amendments.Stage1VisitChange IS NULL OR Amendments.Stage1VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 2),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage1VisitChange) AS INT)
				END
			WHEN rs.Number = N'2'  THEN 
				CASE  
					WHEN (Amendments.Stage2VisitChange IS NULL OR Amendments.Stage2VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 3),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage2VisitChange) AS INT)
				END
			WHEN rs.Number = N'3'  THEN 
				CASE 
					WHEN (Amendments.Stage3VisitChange IS NULL OR Amendments.Stage3VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 4),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage3VisitChange) AS INT)
				END
			WHEN rs.Number = N'4'   THEN 
				CASE 
					WHEN (Amendments.Stage4VisitChange IS NULL OR Amendments.Stage4VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 5),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage4VisitChange) AS INT)
				END

			WHEN rs.Number = N'5'  THEN
				CASE 
					WHEN (Amendments.Stage5VisitChange IS NULL OR Amendments.Stage5VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 7),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage5VisitChange) AS INT)
				END
			WHEN rs.Number = N'6'  THEN 
				CASE 
					WHEN (Amendments.Stage6VisitChange IS NULL OR Amendments.Stage6VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 8),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage6VisitChange) AS INT)
				END
			WHEN rs.Number = N'7'  THEN 
				CASE 
					WHEN (Amendments.Stage7VisitChange IS NULL OR Amendments.Stage7VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 9),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage7VisitChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99'   THEN 
			    CASE 
					WHEN (Amendments.PreConstructionStageVisitChange IS NULL OR Amendments.PreConstructionStageVisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
					AS INT)
					ELSE CAST(SUM(Amendments.PreConstructionStageVisitChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999'  THEN
				CASE 
					WHEN (Amendments.ConstructionStageVisitChange IS NULL OR Amendments.ConstructionStageVisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 11),0)
					AS INT)
					ELSE CAST(SUM(Amendments.ConstructionStageVisitChange) AS INT)
				END
			ELSE CAST(
						ISNULL((SELECT SUM(ISNULL(qs.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi 
								LEFT JOIN SSop.QuoteSections qs ON (qs.ID = qi.QuoteSectionId)
							WHERE qi.CreatedJobId = j.ID),0)
					AS INT)
		END AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		)	  AS CompletedSiteVisits,
		j.ID  AS JobId,
		rs.ID AS StageId
FROM
		SJob.Jobs AS j
CROSS JOIN
		SJob.RibaStages AS rs
LEFT JOIN
		SJob.Activities AS a ON (a.RibaStageId = rs.ID)
				AND (a.JobId = j.ID)
				AND	(a.RowStatus NOT IN (0, 254))
OUTER APPLY
		(
			SELECT
					td.Net *
							CASE
									WHEN tt.IsNegated = 1 THEN
										-1
									ELSE
									1
							END AS Net
			FROM
					SFin.TransactionDetails AS td
			JOIN
					SFin.Transactions AS t ON (t.ID = td.TransactionID)
			JOIN
					SFin.TransactionTypes AS tt ON (tt.ID = t.TransactionTypeID)
			WHERE
					(td.ActivityID = a.ID)
					AND (tt.IsBank = 0)
					AND (td.RowStatus NOT IN (0, 254))
					AND (t.RowStatus NOT IN (0, 254))
		) AS td

OUTER APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change)		   AS Stage0Change,
					SUM(fa.RibaStage1Change)		   AS Stage1Change,
					SUM(fa.RibaStage2Change)		   AS Stage2Change,
					SUM(fa.RibaStage3Change)		   AS Stage3Change,
					SUM(fa.RibaStage4Change)		   AS Stage4Change,
					SUM(fa.RibaStage5Change)		   AS Stage5Change,
					SUM(fa.RibaStage6Change)		   AS Stage6Change,
					SUM(fa.RibaStage7Change)		   AS Stage7Change,
					SUM(fa.PreConstructionStageChange) AS PreConstructionStageChange,
					SUM(fa.ConstructionStageChange)	   AS ConstructionStageChange,
					SUM(fa.FeeCapChange)			   AS FeeCapChange,

					SUM(fa.RibaStage0VisitChange)      AS Stage0VisitChange,
					SUM(fa.RibaStage1VisitChange)      AS Stage1VisitChange,
					SUM(fa.RibaStage2VisitChange)      AS Stage2VisitChange,
					SUM(fa.RibaStage3VisitChange)      AS Stage3VisitChange,
					SUM(fa.RibaStage4VisitChange)      AS Stage4VisitChange,
					SUM(fa.RibaStage5VisitChange)      AS Stage5VisitChange,
					SUM(fa.RibaStage6VisitChange)      AS Stage6VisitChange,
					SUM(fa.RibaStage7VisitChange)      AS Stage7VisitChange,

					SUM(fa.RibaStage0MeetingChange)    AS Stage0MeetingChange,
					SUM(fa.RibaStage1MeetingChange)    AS Stage1MeetingChange,
					SUM(fa.RibaStage2MeetingChange)    AS Stage2MeetingChange,
					SUM(fa.RibaStage3MeetingChange)    AS Stage3MeetingChange,
					SUM(fa.RibaStage4MeetingChange)    AS Stage4MeetingChange,
					SUM(fa.RibaStage5MeetingChange)    AS Stage5MeetingChange,
					SUM(fa.RibaStage6MeetingChange)    AS Stage6MeetingChange,
					SUM(fa.RibaStage7MeetingChange)    AS Stage7MeetingChange,

					SUM(fa.PreConstructionStageMeetingChange) 	  AS PreConstructionStageMeetingChange,
					SUM(fa.PreConstructionStageVisitChange)		  AS PreConstructionStageVisitChange,
					SUM(fa.ConstructionStageMeetingChange)		  AS ConstructionStageMeetingChange, 
					SUM(fa.ConstructionStageVisitChange)		  AS ConstructionStageVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
					AND (ja.RibaStageId = rs.ID)
		) AS Meetings
WHERE
		(rs.ID > 0)
		AND (
				(
						(rs.IsRealStage = 1)
						AND (
								(j.PreConstructionStageFee = 0)
								AND (j.ConstructionStageFee = 0)
						)
				)
				OR (
						(rs.IsRealStage = 0)
						AND (
								(j.PreConstructionStageFee <> 0)
								OR (j.ConstructionStageFee <> 0)
						)
				)
		)
GROUP BY
		rs.Number,
		rs.Description,
		rs.ID,
		j.RibaStage1Fee,
		j.RibaStage2Fee,
		j.RibaStage3Fee,
		j.RibaStage4Fee,
		j.RibaStage5Fee,
		j.RibaStage6Fee,
		j.RibaStage7Fee,
		j.PreConstructionStageFee,
		j.ConstructionStageFee,
		j.FeeCap,
		j.RowStatus,
		j.Guid,
		j.ID,
		Amendments.Stage0Change,
		Amendments.Stage1Change,
		Amendments.Stage2Change,
		Amendments.Stage3Change,
		Amendments.Stage4Change,
		Amendments.Stage5Change,
		Amendments.Stage6Change,
		Amendments.Stage7Change,
		--NEW
		Amendments.Stage0MeetingChange,
		Amendments.Stage1MeetingChange,
		Amendments.Stage2MeetingChange,
		Amendments.Stage3MeetingChange,
		Amendments.Stage4MeetingChange,
		Amendments.Stage5MeetingChange,
		Amendments.Stage6MeetingChange,
		Amendments.Stage7MeetingChange,
		--NEW
		Amendments.Stage0VisitChange,
		Amendments.Stage1VisitChange,
		Amendments.Stage2VisitChange,
		Amendments.Stage3VisitChange,
		Amendments.Stage4VisitChange,
		Amendments.Stage5VisitChange,
		Amendments.Stage6VisitChange,
		Amendments.Stage7VisitChange,

		Amendments.PreConstructionStageChange,
		Amendments.ConstructionStageChange,
		--NEW
		Amendments.PreConstructionStageMeetingChange,
		Amendments.PreConstructionStageVisitChange,
		Amendments.ConstructionStageMeetingChange,
		Amendments.ConstructionStageVisitChange,

		Amendments.FeeCapChange,
		Meetings.MeetingTotal,
		Meetings.SiteVisitTotal
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (ex. Fee Cap.)',
		N'Total (ex. Fee Cap.)',
		-- Agreed
		Quoted.Total 
		+ ISNULL(Amendments.TotalChange,
		0
		),
		-- Invoiced
		ISNULL(jf.InvoicedValue,
		0
		),
		-- Remaining j.AgreedFee
		Quoted.Total 
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-2
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qs.NumberOfMeetings)   Meetings,
					SUM(qs.NumberOfSiteVisits) SiteVisits,
					SUM(qi.Net * qi.Quantity) Total
					
			FROM
					SSop.QuoteItems AS qi
			LEFT JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
		) AS Quoted
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (inc. Fee Cap)',
		N'Total (inc. Fee Cap)',
		--Agreed
		Quoted.Total + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		Quoted.Total +  j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-3
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange + fa.FeeCapChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					-- CBLD-587
					--SUM(qs.NumberOfMeetings)   Meetings,
					--SUM(qs.NumberOfSiteVisits) SiteVisits
					SUM(qi.NumberOfMeetings)   Meetings,
					SUM(qi.NumberOfSiteVisits) SiteVisits,
					SUM(qi.Net * qi.Quantity) Total

			FROM
					SSop.QuoteItems AS qi
			JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) AS Quoted
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_CDM_MyProjects]
--
GO



CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_CDM_MyProjects]
	(
		@UserID INT
	)
RETURNS TABLE
 --WITH SCHEMABINDING
AS
RETURN SELECT	
		j.ID																AS ID,
		j.Guid																AS Guid,
		j.RowStatus															AS RowStatus,

																			--[PROJECT]
		ProjectRef.ProjectRef												AS projectRef,						
		client.Name + N' / ' + agent.Name 									AS clientAgent,						
		p.Name + N' / ' + p.FormattedAddressComma							AS propertyName ,					
		CDMRole.jobRole														AS CDMRole,							
		jobstatus.JobStatus													AS jobStatus,						

																			--[FINANCE]
		TotalAgreedFee.Agreed												AS totalAgreed,
		Remaining.Remaining													AS totalRemaining,

																			--[AGREED DELIVERABLES]
		preconmeetings.QuotedMeetings										AS preconMeetings,
		conmeetings.QuotedMeetings											AS conMeetings,
		compliancevisits.compliancevisits									AS complianceVisit,
		HSFile.HSFile														AS hsFile,

																			--[REMAINING DELIVERABLES]
		remainingprecon.remainingPreCon										AS preconMeetingsRemaining,
		remainingconmeetings.reaminingCon									AS conMeetingsRemaining,
		remainingCompVisits.remainingCompVisits								AS compVisitsRemaining,
		HSIssued.HSIssued													AS HSIssued,

																			--[NO HEADER] => [ Client Duties Issued + CDM Strategy Issued]
		clientDutiesIssued.CDIssued											AS clientDutiesIssued,
		CDMStrategyIssued.CDMStratIssued									AS CDMStrategyIssued,

																			--[PCI]
		PCIInspectionCompleted.PCICompleted									AS PCIInspectionCompleted,
		PCIDateCompleted.PCIDate											AS PCIDate,
		--TODO:: PCI VERSION

																			--[RISK]
		DRRLastIssued.DRRLastIssued											AS DRRLastIssued,

																			--[F10]
		F10Applicable.F10Applicable											AS F10Applicable,
		F10IssuedDate.F10Issued												AS F10IssuedDate,
		F10StartDate.F10StartDate											AS F10Start,
		F10WeekDuration.F10WeekDuration										AS F10WeekDuration,
		F10ExpiryDate.F10ExpiryDate											AS F10ExpiryDate,

																			--[CPP]
		CPPDateReceived.CPPDateReceived										AS CPPDateReceived,
		CPPReviewed.CPPReviewed												AS CPPReviewed,			


																			--[PROGRAMME]


																			--[H&S File]
		HSFReviewedDate.HSFReviewedDate										AS HSFReviewed,
		HSFCompletedDate.HSFCompleted										AS HSFCompleted


FROM		SJob.Jobs AS j
JOIN		SJob.JobStatus	AS js ON (js.ID = j.ID)
JOIN		SJob.Properties AS p ON (p.ID = j.UprnID)
JOIN		SJob.JobTypes	AS t ON (t.ID = j.JobTypeID)
JOIN		SCrm.Accounts	AS client ON (client.ID = j.ClientAccountID)
JOIN		SCrm.Accounts	AS agent ON (agent.ID = j.AgentAccountID)
JOIN		SJob.JobStatus  AS jobstatus ON (j.ID = jobstatus.ID)


	OUTER APPLY
	(
		SELECT CASE
			WHEN EXISTS
			(
				SELECT 1
				FROM SSop.Projects AS p
				WHERE p.ID = 59158 AND p.ExternalReference = ''
			)
			THEN j.ProjectId
			ELSE 
				(
					SELECT (CAST(j.ProjectId AS NVARCHAR(15)) + N' - ' + CAST(j.ExternalReference AS NVARCHAR(50)))
				)
			END AS ProjectRef
	) AS ProjectRef																			--Project Reference


	OUTER APPLY 
	(
		SELECT jt.Name AS jobRole
		FROM SJob.JobTypes as jt
		WHERE jt.ID = j.JobTypeID
	) AS CDMRole


		--[FINANCE]
	OUTER APPLY
		(
			SELECT jobfee.Agreed
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = -2 AND jobfee.JobId = j.ID
		) AS TotalAgreedFee																		--Total Agreed Fee
	OUTER APPLY
		(
			SELECT jobfee.Remaining
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = -2 AND jobfee.JobId = j.ID
		) AS Remaining																		--Remaining Fee
					
					
		--[AGREED DELIVERABLES]
		OUTER APPLY
		(
			SELECT jobfee.QuotedMeetings
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 10 AND jobfee.JobId = j.ID
		) AS preconmeetings																	--Pre-Con. Meetings
		
		OUTER APPLY
		(
			SELECT jobfee.QuotedMeetings
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 11 AND jobfee.JobId = j.ID
		) AS conmeetings																	--Con. Meetings
		
		OUTER APPLY
		(
			SELECT COUNT(act.ID) AS compliancevisits
			FROM SJob.Activities AS act 
			WHERE act.ActivityTypeID = 23 AND act.JobID = j.ID 
		) AS compliancevisits																--Compliance Visits
		
		OUTER APPLY
		(
			SELECT CASE
				WHEN EXISTS
				(
					SELECT 1 FROM Sjob.Milestones AS m
					WHERE m.MilestoneTypeID = 8 AND m.JobID = j.ID
				) 
			THEN N'Yes'
			ELSE N'No'
			END AS HSFile
		) AS HSFile																			--H&S File (Yes/No)
		

		--[REMAINING DELIVERABLES]
		OUTER APPLY
		(
			SELECT (jobfee.QuotedMeetings - jobfee.CompletedMeetings) AS remainingPreCon
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 10 AND jobfee.JobId = j.ID
		) AS remainingprecon																	--Pre-con Mtgs remaining.

		OUTER APPLY
		(
			
			SELECT (jobfee.QuotedMeetings - jobfee.CompletedMeetings) as reaminingCon
			FROM SJob.Job_FeeDrawdown AS jobfee
			WHERE jobfee.StageId = 11 AND jobfee.JobId = j.ID
	
		) AS remainingconmeetings																--Con Mtgs remaining.

		OUTER APPLY
		(
			SELECT 
				(COUNT(Act.ID) - 
					(SELECT COUNT(Act.ID) -- use primary key
					 FROM SJob.Activities AS Act 
					 WHERE Act.ActivityTypeID = 23 
					   AND Act.JobID = j.ID 
					   AND Act.ActivityStatusID = 3)
				) AS remainingCompVisits
			FROM SJob.Activities AS Act 
			WHERE Act.ActivityTypeID = 23 
			  AND Act.JobID = j.ID

		) AS remainingCompVisits																--Compliance visits

		OUTER APPLY 
		(
			SELECT CASE
			WHEN EXISTS
			(
				SELECT 1
				FROM SJob.Milestones AS bool
				WHERE JobID = j.ID AND MilestoneTypeID = 8 AND IsComplete = 1
			)
			THEN N'Yes'
			ELSE N'No'
			END AS HSIssued																		--H&S Issued

		) AS HSIssued

		OUTER APPLY 
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 2 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS CDIssued
		) AS clientDutiesIssued																	--Client Duties Issued

		OUTER APPLY 
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 1 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS CDMStratIssued
		) AS CDMStrategyIssued																	--CDM Strategy Issued

		OUTER APPLY
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1 
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 11 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN N'Yes'
			ELSE N'No'
			END AS PCICompleted
		) AS PCIInspectionCompleted																		-- PCI Inspection Completed

		OUTER APPLY
		(
			SELECT CASE 
			WHEN EXISTS
			(
				SELECT 1
				FROM Sjob.Milestones AS m
				WHERE m.MilestoneTypeID = 11 AND m.IsComplete = 1  AND m.JobID = j.ID
			)
			THEN (SELECT CAST(m.CompletedDateTimeUTC AS DATE) FROM Sjob.Milestones AS m WHERE m.MilestoneTypeID = 11 AND m.JobID = j.ID)
			ELSE NULL
			END AS PCIDate
		) AS PCIDateCompleted																			-- PCI/PDI Date


		--OUTER APPLY 
		--(
		
		--) AS PCIVersion																				--PCI Version ============ TODOD!!!! ============

		OUTER APPLY 
		(
			SELECT CASE
			WHEN EXISTS
			(
				SELECT 1 
				FROM SJob.Activities AS act
				WHERE act.JobID = j.ID AND act.ActivityTypeID = 26 AND act.ActivityStatusID = 3
			)
			THEN (SELECT CAST(act.EndDate AS DATE) FROM Sjob.Activities AS act WHERE act.JobID = j.ID AND act.ActivityTypeID = 26 AND act.ActivityStatusID = 3) 
			ELSE NULL 
			END AS DRRLastIssued
		) AS DRRLastIssued																				--DRR Last Issued


		OUTER APPLY
		(
			SELECT CASE 
				WHEN EXISTS
				(
					SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
				)
				THEN N'Yes'
				ELSE N'No'
			END AS F10Applicable
		) AS F10Applicable																				--F10 Applicable

		OUTER APPLY
		(
			SELECT CASE
			WHEN EXISTS
				(
					SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
				)
				THEN 
				(
					SELECT CAST(CAST(m.CompletedDateTimeUTC AS DATE) AS VARCHAR)
					FROM SJob.Milestones AS m
					WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
				)
				ELSE N'#808080' -- return grey hex 
			END AS F10Issued
		) AS F10IssuedDate																				--F10 Issued Date

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(CAST(m.StartDateTimeUTC AS DATE) AS VARCHAR)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
			END AS F10StartDate
		) AS F10StartDate																			--F10 Start Date

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(DATEDIFF(WEEK, CAST(m.StartDateTimeUTC AS DATE), CAST(m.DueDateTimeUTC AS DATE)) AS VARCHAR) 
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
				END AS F10WeekDuration
		) AS F10WeekDuration																		--F10 Duration (wks)

		OUTER APPLY 
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 7
					)
					THEN 
					(
						SELECT CAST(CAST(m.SubmissionExpiryDate AS DATE) AS VARCHAR)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 7 AND JobID = j.ID
					)
					ELSE N'#808080'
			END AS F10ExpiryDate
		) AS F10ExpiryDate																			--F10 Expiry Date

		OUTER APPLY
		(
			SELECT CASE
					WHEN EXISTS
						(
							SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 19
						)
						THEN 
						(
							SELECT CAST(m.CompletedDateTimeUTC AS DATE)
							FROM SJob.Milestones AS m
							WHERE m.MilestoneTypeID = 19 AND JobID = j.ID
						)
						ELSE NULL
				END AS CPPDateReceived
		) AS CPPDateReceived																		-- CPP Date / Received	

		OUTER APPLY
		(
			SELECT CASE
				WHEN EXISTS
					(
						SELECT 1 FROM SJob.Milestones WHERE JobID = j.ID AND MilestoneTypeID = 17
					)
					THEN 
					(
						SELECT CAST(m.CompletedDateTimeUTC AS DATE)
						FROM SJob.Milestones AS m
						WHERE m.MilestoneTypeID = 17 AND JobID = j.ID
					)
					ELSE NULL
			END AS CPPReviewed
		) AS CPPReviewed																			-- CPP Reviewed 

		--OUTER APPLY
		--(
		
		--) AS ConstructionStartDate																-- Construction Start Date =======> [TODO]

		--OUTER APPLY
		--(
		
		--) AS ConstructionCompletionDate															-- Construction Completion Date =======> [TODO]

		--OUTER APPLY
		--(
		
		--) AS ConstuctionDuration																	-- (Construction) Duration (wks) =======> [TODO]

		OUTER APPLY
		(
			SELECT CAST(m.ReviewedDateTimeUTC AS DATE) AS HSFReviewedDate
			FROM SJob.Milestones as m 
			WHERE m.MilestoneTypeID = 8 AND  m.JobID = j.ID
		) AS HSFReviewedDate																		--HSF Reviewed

		OUTER APPLY
		(
			SELECT CAST(m.CompletedDateTimeUTC AS DATE) AS HSFCompleted
			FROM SJob.Milestones as m 
			WHERE m.MilestoneTypeID = 8 AND  m.JobID = j.ID
		) AS HSFCompletedDate																		--HSF Completed
		
		
WHERE (j.IsActive	  = 1)
		AND (EXISTS
		(
			SELECT	1
			FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
															@UserID
														) AS oscr
		)
			)
		AND (j.RowStatus NOT IN (0, 254))
		AND (j.SurveyorID = @UserID)
		AND (j.ID		  > 0);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Refresh view [SSop].[Project_ExtendedInfo]
--
EXEC sp_refreshview '[SSop].[Project_ExtendedInfo]'
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Commit Transaction
--
IF @@TRANCOUNT>0 COMMIT TRANSACTION
